#include <stdio.h>
#include <math.h>

int main(void) {
    double x1, y1, x2, y2;
    if (scanf("%lf %lf %lf %lf", &x1, &y1, &x2, &y2) != 4) return 0;
    double dx = x2 - x1, dy = y2 - y1;
    printf("distance = %.3f\n", sqrt(dx * dx + dy * dy));
    printf("midpoint = %.3f %.3f\n", (x1 + x2) / 2.0, (y1 + y2) / 2.0);
    return 0;
}
